import React from 'react';

function LogementHost() {
    return (
        <div className="logement__host">
            <h3>Alexandre Dumas</h3>
            <div className="logement__host__badge"></div>
            <div className="logement__host__rating">
                <span>★</span>
                <span>★</span>
                <span>★</span>
                <span>☆</span>
                <span>☆</span>
            </div>
        </div>
    );
}

export default LogementHost;
